<template>
  <section v-if="formattedData.length > 0" class="metadata">
    <component :is="headerTag" v-if="title">{{ titleText }}</component>
    <template v-if="isGeoparquet">
      <b-card-group columns :class="`count-${primaryGroups.length}`" v-if="primaryGroups.length > 0">
        <MetadataGroup
          v-for="group in primaryGroups"
          :key="group.extension"
          v-bind="group"
        />
      </b-card-group>
      <div v-if="additionalGroups.length > 0" class="additional-metadata-section">
        <div class="additional-metadata-header" @click="additionalOpen = !additionalOpen">
          <h3 class="mb-0">{{ $t('metadata.additional') || 'Additional Metadata' }}</h3>
          <BIconChevronDown v-if="!additionalOpen" />
          <BIconChevronUp v-else />
        </div>
        <b-collapse v-model="additionalOpen">
          <b-card-group columns :class="`count-${additionalGroups.length}`">
            <MetadataGroup
              v-for="group in additionalGroups"
              :key="group.extension"
              v-bind="group"
            />
          </b-card-group>
        </b-collapse>
      </div>
    </template>
    <b-card-group v-else columns :class="`count-${formattedData.length}`">
      <MetadataGroup
        v-for="group in formattedData"
        :key="group.extension"
        v-bind="group"
      />
    </b-card-group>
  </section>
</template>

<script>
import { BCardGroup, BCollapse } from 'bootstrap-vue-next';
import BIconChevronDown from '~icons/bi/chevron-down';
import BIconChevronUp from '~icons/bi/chevron-up';
import {
  formatAsset,
  formatCatalog,
  formatCollection,
  formatGrouped,
  formatItemProperties,
  formatLink,
  formatProvider,
  formatSummaries,
} from "@radiantearth/stac-fields";
import StacFieldsMixin from './StacFieldsMixin';
import MetadataGroup from "./metadata/MetadataGroup.vue";
import { isoDuration } from "@musement/iso-duration";
import { mapState } from "vuex";
// Register custom fields for the metadata rendering
 
import "../../fields.config";

export default {
  name: "MetadataGroups",
  components: {
    BCardGroup,
    BCollapse,
    BIconChevronDown,
    BIconChevronUp,
    MetadataGroup,
  },
  mixins: [
    StacFieldsMixin({}),
  ],
  props: {
    data: {
      type: Object,
      required: true,
    },
    type: {
      type: String,
      required: true,
    },
    ignoreFields: {
      type: Array,
      default: () => [],
    },
    title: {
      type: [Boolean, String],
      default: true,
    },
    headerTag: {
      type: String,
      default: "h2",
    },
  },
  data() {
    return {
      formattedData: [],
      additionalOpen: false,
    };
  },
  computed: {
    ...mapState(["uiLanguage"]),
    titleText() {
      if (typeof this.title === "string") {
        return this.title;
      }
      return this.$t("metadata.title");
    },
    isGeoparquet() {
      return this.type === 'Collection' && this.formattedData.some(g => g.extension === 'geoparquet');
    },
    primaryGroups() {
      return this.formattedData.filter(g => g.extension === 'table');
    },
    additionalGroups() {
      return this.formattedData.filter(g => g.extension !== 'table');
    },
  },
  watch: {
    // We need to run this.formatData() once at the beginning.
    // We use the uiLanguage watcher for this and enable it through immediate: true,
    // because this ensures that the duration.js from the locales is loaded properly.
    // We don't set immediate: true for the data watcher,
    // because this would cause formatting to run twice at the beginning.
    uiLanguage: {
      immediate: true,
      async handler(locale) {
        if (!locale) {
          return;
        }

        // Update durations (for stac-fields)
        const en = (await import(`../locales/${locale}/duration.js`)).default;
        isoDuration.setLocales({ en });

        // Format the data again to update translations
        this.formattedData = this.formatData();
      },
    },
    data() {
      this.formattedData = this.formatData();
    },
  },
  methods: {
    formatData() {
      // Filter all fields as given in ignoreFields and also
      // ignore fields starting with an underscore which is likely originating from the STAC class
      let filter = (key) =>
        !key.startsWith("_") && !this.ignoreFields.includes(key);

      const data = typeof this.data?.toJSON === "function" ? this.data.toJSON() : this.data;
      const context = typeof this.data?.getContext === "function" ? this.data.getContext() : null;

      switch (this.type) {
        case "Asset":
          return formatAsset(data, context, filter);
        case "Link":
          return formatLink(data, context, filter);
        case "Provider":
          return formatProvider(data, context, filter);
        case "Item":
          return formatItemProperties(data, filter);
        case "Catalog":
          return formatCatalog(data, filter);
        case "Collection": {
          const core = formatCollection(data, filter);
          const summaries = formatSummaries(data, filter);
          // Merge summaries into collection metadata
          summaries.forEach((summaryGroup) => {
            let index = core.findIndex(
              (coreGroup) => summaryGroup.extension === coreGroup.extension
            );
            if (index !== -1) {
              Object.assign(core[index].properties, summaryGroup.properties);
            } else {
              core.push(summaryGroup);
            }
          });
          const collator = new Intl.Collator(this.uiLanguage);
          return core.sort((a, b) => collator.compare(a.label, b.label));
        }
        case "FeatureCollection":
          return {};
        default:
          return formatGrouped(context, data, this.type, filter);
      }
    },
  },
};
</script>

